package apikeys

import (
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"strconv"
	"time"

	"github.com/google/uuid"
	"github.com/harusame0616/ijuku/apps/api/lib/response"
)

type generateApiKey struct {
	usecase generateApiKeyUsecase
}

func NewGenerateApiKeyHandler(usecase generateApiKeyUsecase) generateApiKey {
	return generateApiKey{
		usecase: usecase,
	}
}

func (generateApiKey generateApiKey) GenerateApiKeyHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	// TODO 認証

	userID := r.PathValue("userID")
	if userID == "" {
		// パスで UserID がマッピングされているのでこのパスは通過しない前提
		// ここを通過する場合はパスのマッピングが間違っているなどの不具合の可能性
		response.WriteInternalServerErrorResponse(w)
		return
	}

	parsedUserID, err := uuid.Parse(userID)
	if err != nil {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "User ID must be valid UUID")
		return
	}

	var bodyParams struct {
		ExpiredAt *time.Time `json:"expiredAt"`
	}

	defer r.Body.Close()
	if err := json.NewDecoder(r.Body).Decode(&bodyParams); err != nil {
		var timeParseErr *time.ParseError

		switch {
		case errors.As(err, &timeParseErr):
			response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "expiredAt must be ISO 8601 format")
		default:
			response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "Body must be valid JSON")
		}
		return
	}

	result, err := generateApiKey.usecase.Execute(r.Context(), parsedUserID, bodyParams.ExpiredAt)

	if err != nil {
		switch {
		case errors.Is(err, ErrApiKeyCountExceedsLimit):
			response.WriteErrorResponse(w, http.StatusConflict, "APIKEY_QUOTA_EXCEEDS_LIMIT", "Api key quota exceeds limit. Api key quota limit is "+strconv.Itoa(apiKeyMaxCount))
		default:
			fmt.Printf("err %v", err)
			response.WriteInternalServerErrorResponse(w)
		}

		return
	}

	json.NewEncoder(w).Encode(result)
}
package apikeys

import (
	"context"
	"time"

	"github.com/google/uuid"
)

type generateApiKeyRepository interface {
	count(ctx context.Context, userId uuid.UUID) int
	save(ctx context.Context, apiKey hashedApiKey) error
}

type generateApiKeyUsecase struct {
	apiKeyRepository generateApiKeyRepository
}

func NewGenerateApiKeyUsecase(repository generateApiKeyRepository) generateApiKeyUsecase {
	return generateApiKeyUsecase{apiKeyRepository: repository}
}

type generateApiKeyExecuteResult struct {
	Apikey string `json:"apikey"`
}

func (usecase *generateApiKeyUsecase) Execute(ctx context.Context, userId uuid.UUID, expiredAt *time.Time) (generateApiKeyExecuteResult, error) {
	// 不変条件が上限チェックのみのため、Usecase 層でチェックする
	// 複数の不変条件が加わる場合は UserApiKeys ドメインコレクションへの昇格を検討する
	userApiKeyCount := usecase.apiKeyRepository.count(ctx, userId)
	if userApiKeyCount >= apiKeyMaxCount {
		return generateApiKeyExecuteResult{}, ErrApiKeyCountExceedsLimit
	}

	hashedApiKey, plainApiKey := NewHashedApiKey(NewHashedApiKeyParams{
		UserID:    userId,
		ExpiredAt: expiredAt,
	})

	if err := usecase.apiKeyRepository.save(ctx, hashedApiKey); err != nil {
		return generateApiKeyExecuteResult{}, err
	}

	return generateApiKeyExecuteResult{
		Apikey: plainApiKey,
	}, nil
}
package apikeys

import (
	"context"

	"github.com/google/uuid"
	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgtype"
)

type sqrcQueries interface {
	InsertApiKey(ctx context.Context, arg db.InsertApiKeyParams) error
	CountApiKeyByUserID(ctx context.Context, userid pgtype.UUID) (int64, error)
}

type ApiKeySqrcRepository struct {
	queries sqrcQueries
}

func NewApiKeySqrcRepository(sqrc sqrcQueries) ApiKeySqrcRepository {
	return ApiKeySqrcRepository{queries: sqrc}
}

func (repo ApiKeySqrcRepository) count(ctx context.Context, userId uuid.UUID) int {
	pgUserID := pgtype.UUID{Bytes: userId, Valid: true}
	count, err := repo.queries.CountApiKeyByUserID(ctx, pgUserID)
	if err != nil {
		return 0
	}
	return int(count)
}

func (repo ApiKeySqrcRepository) save(ctx context.Context, apiKey hashedApiKey) error {
	apikeyID := pgtype.UUID{Bytes: apiKey.apiKeyID, Valid: true}
	userID := pgtype.UUID{Bytes: apiKey.userID, Valid: true}

	var expiredAt pgtype.Timestamptz
	if apiKey.expiredAt == nil {
		expiredAt = pgtype.Timestamptz{
			InfinityModifier: pgtype.Infinity,
			Valid:            true,
		}
	} else {
		expiredAt = pgtype.Timestamptz{
			Time:  *apiKey.expiredAt,
			Valid: true,
		}
	}

	return repo.queries.InsertApiKey(ctx, db.InsertApiKeyParams{
		ApikeyID:       apikeyID,
		KeyHash:        apiKey.hashedApiKey,
		UserID:         userID,
		KeyPlainSuffix: apiKey.plainApiKeySuffix,
		ExpiredAt:      expiredAt,
	})
}

