package auth

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
)

type SupabaseClient struct {
	baseURL  string
	anonKey  string
	http     *http.Client
}

func NewSupabaseClient(baseURL, anonKey string) *SupabaseClient {
	return &SupabaseClient{
		baseURL: strings.TrimRight(baseURL, "/"),
		anonKey: anonKey,
		http:    http.DefaultClient,
	}
}

// BuildAuthorizeURL builds the Supabase /auth/v1/authorize URL for PKCE OAuth.
func (c *SupabaseClient) BuildAuthorizeURL(provider, redirectTo, codeChallenge, state string) string {
	q := url.Values{}
	q.Set("provider", provider)
	q.Set("redirect_to", redirectTo)
	q.Set("code_challenge", codeChallenge)
	q.Set("code_challenge_method", "s256")
	q.Set("state", state)
	return c.baseURL + "/auth/v1/authorize?" + q.Encode()
}

type TokenResponse struct {
	AccessToken  string `json:"access_token"`
	RefreshToken string `json:"refresh_token"`
	ExpiresIn    int64  `json:"expires_in"`
	TokenType    string `json:"token_type"`
	User         struct {
		ID               string            `json:"id"`
		Email            string            `json:"email"`
		UserMetadata     map[string]any    `json:"user_metadata"`
	} `json:"user"`
}

// ExchangePKCE exchanges an authorization code and verifier for tokens.
func (c *SupabaseClient) ExchangePKCE(ctx context.Context, code, codeVerifier string) (*TokenResponse, error) {
	body, _ := json.Marshal(map[string]string{
		"auth_code":     code,
		"code_verifier": codeVerifier,
	})
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, c.baseURL+"/auth/v1/token?grant_type=pkce", strings.NewReader(string(body)))
	if err != nil {
		return nil, err
	}
	req.Header.Set("apikey", c.anonKey)
	req.Header.Set("Content-Type", "application/json")

	res, err := c.http.Do(req)
	if err != nil {
		return nil, err
	}
	defer res.Body.Close()

	if res.StatusCode != http.StatusOK {
		b, _ := io.ReadAll(res.Body)
		return nil, fmt.Errorf("supabase token exchange failed: status=%d body=%s", res.StatusCode, string(b))
	}

	var tr TokenResponse
	if err := json.NewDecoder(res.Body).Decode(&tr); err != nil {
		return nil, err
	}
	return &tr, nil
}

// Logout revokes the session for the given access token.
func (c *SupabaseClient) Logout(ctx context.Context, accessToken string) error {
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, c.baseURL+"/auth/v1/logout", nil)
	if err != nil {
		return err
	}
	req.Header.Set("apikey", c.anonKey)
	req.Header.Set("Authorization", "Bearer "+accessToken)

	res, err := c.http.Do(req)
	if err != nil {
		return err
	}
	defer res.Body.Close()

	if res.StatusCode >= 400 {
		b, _ := io.ReadAll(res.Body)
		return fmt.Errorf("supabase logout failed: status=%d body=%s", res.StatusCode, string(b))
	}
	return nil
}

